28: public enum MemberState {
29:     /**
30:      * The member is fully reconciled with the desired target assignment.
31:      */
32:     STABLE((byte) 0),
33: 
34:     /**
35:      * The member must revoke some partitions in order to be able to
36:      * transition to the next epoch.
37:      */
38:     UNREVOKED_PARTITIONS((byte) 1),
39: 
40:     /**
41:      * The member transitioned to the last epoch but waits on some
42:      * partitions which have not been revoked by their previous
43:      * owners yet.
44:      */
45:     UNRELEASED_PARTITIONS((byte) 2),
46: 
47:     /**
48:      * The member is in an unknown state. This can only happen if a future
49:      * version of the software introduces a new state unknown by this version.
50:      */
51:     UNKNOWN((byte) 127);
52: 
53:     private static final Map<Byte, MemberState> VALUES_TO_ENUMS = new HashMap<>();
54: 
55:     static {
56:         for (MemberState state: MemberState.values()) {
57:             VALUES_TO_ENUMS.put(state.value(), state);
58:         }
59:     }
60: 
61:     private final byte value;
62: 
63:     MemberState(byte value) {
64:         this.value = value;
65:     }
66: 
67:     public byte value() {
68:         return value;
69:     }
70: 
71:     public static MemberState fromValue(byte value) {
72:         MemberState state = VALUES_TO_ENUMS.get(value);
73:         if (state == null) {
74:             return UNKNOWN;
75:         }
76:         return state;
77:     }
78: }
